return [
  {
    json: {
      chat_id: $json.chat_id,
      complexity
    }
  }
];

const input = $('Action Router').first().json;
const session = $('Get Session').first().json;

const hours = Number(String(input.text || '').replace(',', '.'));

if (!hours || hours <= 0) {
  return [{
    json: {
      success: false,
      chat_id: input.chat_id,
      message: '❌ Введіть коректну кількість годин. Наприклад: 4 або 2.5'
    }
  }];
}

if (!session || session.step !== 'waiting_hours') {
  return [{
    json: {
      success: false,
      chat_id: input.chat_id,
      message: '❌ Спочатку натисніть 🆕 Новий розрахунок'
    }
  }];
}

const settingsRows = $('Get Settings').all().map(i => i.json);
const consumablesRows = $('Get Consumables').all().map(i => i.json);
const normsRows = $('Get Usage Norms').all().map(i => i.json);

function n(value) {
  return Number(value || 0);
}

function r(value) {
  return Math.round(value);
}

function pick(row, keys) {
  for (const key of keys) {
    if (row[key] !== undefined && row[key] !== null && row[key] !== '') {
      return row[key];
    }
  }
  return 0;
}

const settings = {};

for (const row of settingsRows) {
  settings[row.key] = n(row.value);
}

const prices = {};

for (const row of consumablesRows) {
  const name = String(row['назва'] || '').trim();
  const price = n(row['ціна_за_одиницю']);
  if (name) {
    prices[name] = price;
  }
}

const type = String(session.type || '').toLowerCase().trim();
const complexity = String(session.complexity || '').toLowerCase().trim();

const norm = normsRows.find(row =>
  String(row['тип'] || '').toLowerCase().trim() === type &&
  String(row['складність'] || '').toLowerCase().trim() === complexity
);

if (!norm) {
  return [{
    json: {
      success: false,
      chat_id: input.chat_id,
      message: `❌ Не знайдено норму витрат для ${type} / ${complexity}`
    }
  }];
}

const details = {
  голки: n(norm['голки']) * n(prices['Голка']),
  картриджі: n(norm['картриджі']) * n(prices['Картридж']),
  фарба_чорна: n(norm['фарба_чорна_мл']) * n(prices['Фарба чорна']),
  фарба_кольорова: n(norm['фарба_кольорова_мл']) * n(prices['Фарба кольорова']),
  рукавички: n(norm['рукавички_пари']) * n(prices['Рукавички']),
  плівка: n(norm['плівка_м']) * n(prices['Плівка']),
  ковпачки: n(norm['ковпачки']) * n(prices['Ковпачки']),
  серветки: n(norm['серветки']) * n(prices['Серветки']),
  вазелін: n(norm['вазелін_г']) * n(prices['Вазелін']),
  дезінфектор: n(norm['дезінфектор_мл']) * n(prices['Дезінфектор']),
  пелюшки: n(norm['пелюшки']) * n(prices['Одноразова пелюшка']),
  барерний_захист: n(pick(norm, ['барерний_захист', 'барєрний_захист', 'бар’єрний_захист'])) * n(prices['Бар’єрний захист'])
};

const consumablesTotal = Object.values(details).reduce((sum, value) => sum + value, 0);

const fixedCostsMonth =
  n(settings.rent_month) +
  n(settings.utilities_month) +
  n(settings.ads_month) +
  n(settings.equipment_month);

const workHoursMonth = n(settings.work_hours_month) || 120;
const masterRateHour = n(settings.master_rate_hour) || 700;
const profitMargin = n(settings.profit_margin) || 20;

const studioCost = fixedCostsMonth / workHoursMonth * hours;
const masterPay = masterRateHour * hours;

const costPrice = consumablesTotal + studioCost + masterPay;
const finalPrice = costPrice * (1 + profitMargin / 100);
const profit = finalPrice - costPrice;

return [{
  json: {
    success: true,

    дата: new Date().toISOString().split('T')[0],
    chat_id: input.chat_id,
    username: input.username || '',
    години: hours,
    тип: type,
    складність: complexity,

    картриджі: r(details.картриджі),
    фарба_чорна: r(details.фарба_чорна),
    фарба_кольорова: r(details.фарба_кольорова),
    рукавички: r(details.рукавички),
    плівка: r(details.плівка),
    ковпачки: r(details.ковпачки),
    серветки: r(details.серветки),
    вазелін: r(details.вазелін),
    дезінфектор: r(details.дезінфектор),
    пелюшки: r(details.пелюшки),

    барерний_захист: r(details.барерний_захист),
    барєрний_захист: r(details.барерний_захист),

    витратники_всього: r(consumablesTotal),
    студійні_витрати: r(studioCost),
    оплата_майстра: r(masterPay),
    собівартість: r(costPrice),
    фінальна_ціна: r(finalPrice),
    прибуток: r(profit)
  }
}];

const rows = $('Get Settings For Menu').all().map(i => i.json);
const input = $('Normalize Input').first().json;

const settings = {};

for (const row of rows) {
  settings[row.key] = row.value;
}

const text = `⚙️ Налаштування калькулятора

🏠 Оренда: ${settings.rent_month || 0} грн/міс
⚡ Комунальні: ${settings.utilities_month || 0} грн/міс
📢 Реклама: ${settings.ads_month || 0} грн/міс
🛠 Обладнання: ${settings.equipment_month || 0} грн/міс

🕒 Робочих годин/міс: ${settings.work_hours_month || 0}
👨‍🎨 Ставка майстра: ${settings.master_rate_hour || 0} грн/год
📈 Маржа: ${settings.profit_margin || 0}%

Щоб змінити налаштування — поки редагуй лист Settings у Google Sheets.`;

return [{
  json: {
    chat_id: input.chat_id,
    message: text
  }
}];

